const http = require('http');
const { request } = require('https');
const { URL } = require('url');

const PORT = process.env.PORT || 3000;
const TARGET_URL = process.env.TARGET_URL || '';

function sendCORSHeaders(res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,POST,PUT,PATCH,DELETE,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', '*');
  res.setHeader('Access-Control-Expose-Headers', '*');
}

function proxyRequest(req, res) {
  if (!TARGET_URL) {
    res.statusCode = 500;
    sendCORSHeaders(res);
    res.setHeader('Content-Type', 'application/json');
    res.end(JSON.stringify({ error: 'TARGET_URL is not configured' }));
    return;
  }

  const target = new URL(TARGET_URL);
  const upstreamPath = `${req.url || '/'}`;
  const options = {
    protocol: target.protocol,
    hostname: target.hostname,
    port: target.port || (target.protocol === 'https:' ? 443 : 80),
    method: req.method,
    path: `${target.pathname.replace(/\/$/, '')}${upstreamPath}`,
    headers: {
      ...req.headers,
      host: target.host
    }
  };

  const proxy = request(options, upstreamRes => {
    sendCORSHeaders(res);
    res.statusCode = upstreamRes.statusCode || 502;
    Object.entries(upstreamRes.headers).forEach(([key, value]) => {
      if (
        key.toLowerCase() === 'access-control-allow-origin' ||
        key.toLowerCase() === 'access-control-allow-methods' ||
        key.toLowerCase() === 'access-control-allow-headers' ||
        key.toLowerCase() === 'access-control-expose-headers'
      ) {
        return;
      }
      if (value !== undefined) res.setHeader(key, value);
    });
    upstreamRes.pipe(res);
  });

  proxy.on('error', err => {
    sendCORSHeaders(res);
    res.statusCode = 502;
    res.setHeader('Content-Type', 'application/json');
    res.end(JSON.stringify({ error: 'Bad gateway', details: err.message }));
  });

  req.pipe(proxy);
}

const server = http.createServer((req, res) => {
  sendCORSHeaders(res);

  if (req.method === 'OPTIONS') {
    res.statusCode = 204;
    res.end();
    return;
  }

  proxyRequest(req, res);
});

server.listen(PORT, () => {
  process.stdout.write(`API gateway listening on port ${PORT}\n`);
});